+const reloadStatusFilename = "reload-status.json"
+
+// ReloadStatus describes the outcome of the most recent transactional
+// configuration reload.
+type ReloadStatus struct {
+	LastReloadID       string             `json:"last_reload_id"`
+	LastReloadSuccessful bool              `json:"last_reload_successful"`
+	ErrorCategory      string             `json:"error_category"`
+	ErrorMessage       string             `json:"error_message"`
+	AppliedReloaders   []string           `json:"applied_reloaders"`
+	RollbackAttempted  bool               `json:"rollback_attempted"`
+	RollbackSuccessful bool               `json:"rollback_successful"`
+	FailedReloader     string             `json:"failed_reloader"`
+	ReloaderTimingsMS  map[string]float64 `json:"reloader_timings_ms"`
+}
+
+// ReloadStatusStore keeps reload status available to the API and on disk.
+type ReloadStatusStore struct {
+	mtx  sync.RWMutex
+	path string
+	status ReloadStatus
+}
+
+func NewReloadStatusStore(dir string) *ReloadStatusStore {
+	return &ReloadStatusStore{
+		path: filepath.Join(dir, reloadStatusFilename),
+		status: ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}},
+	}
+}
+
+// Load restores the previous outcome. Invalid or missing files leave the
+// default status intact.
+func (s *ReloadStatusStore) Load() error {
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		if os.IsNotExist(err) {
+			return nil
+		}
+		return err
+	}
+	var status ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil {
+		return err
+	}
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = "none"
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	s.mtx.Lock()
+	s.status = status
+	s.mtx.Unlock()
+	return nil
+}
+
+func (s *ReloadStatusStore) GetReloadStatus() ReloadStatus {
+	s.mtx.RLock()
+	defer s.mtx.RUnlock()
+	status := s.status
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]float64, len(s.status.ReloaderTimingsMS))
+	for k, v := range s.status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[k] = v
+	}
+	return status
+}
+
+// Record saves status atomically. The in-memory status is updated even if the
+// storage directory is temporarily unavailable.
+func (s *ReloadStatusStore) Record(status ReloadStatus) error {
+	if status.LastReloadID == "" {
+		status.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	s.mtx.Lock()
+	s.status = status
+	s.mtx.Unlock()
+
+	b, err := json.Marshal(status)
+	if err != nil {
+		return err
+	}
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err != nil {
+		return err
+	}
+	tmp, err := os.CreateTemp(filepath.Dir(s.path), ".reload-status-*")
+	if err != nil {
+		return err
+	}
+	tmpName := tmp.Name()
+	defer os.Remove(tmpName)
+	if _, err := tmp.Write(b); err != nil {
+		tmp.Close()
+		return err
+	}
+	if err := tmp.Close(); err != nil {
+		return err
+	}
+	return os.Rename(tmpName, s.path)
+}
