+// transactionalConfigReloader applies a candidate configuration one component
+// at a time and restores the last fully applied configuration on failure.
+type transactionalConfigReloader struct {
+	status                    *web.ReloadStatusStore
+	filename                  string
+	enableExemplarStorage     bool
+	logger                    *slog.Logger
+	noStepSubqueryInterval    *safePromQLNoStepSubqueryInterval
+	reloaders                 []reloader
+	lastGood                  *config.Config
+}
+
+func newTransactionalConfigReloader(enabled bool, status *web.ReloadStatusStore, filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, reloaders []reloader) *transactionalConfigReloader {
+	if !enabled {
+		return nil
+	}
+	return &transactionalConfigReloader{
+		status: status, filename: filename, enableExemplarStorage: enableExemplarStorage,
+		logger: logger, noStepSubqueryInterval: noStepSubqueryInterval, reloaders: reloaders,
+	}
+}
+
+func (r *transactionalConfigReloader) Reload(callback func(bool), initial bool) (err error) {
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+	}()
+
+	r.logger.Info("Loading configuration file", "filename", r.filename)
+	conf, err := config.LoadFile(r.filename, agentMode, r.logger)
+	if err != nil {
+		return r.record(initial, web.ReloadStatus{LastReloadSuccessful: false, ErrorCategory: "load_error", ErrorMessage: err.Error()}, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", r.filename, err))
+	}
+	if r.enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	status := web.ReloadStatus{LastReloadSuccessful: false, ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}
+	for _, rl := range r.reloaders {
+		started := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(started)) / float64(time.Millisecond)
+		if err != nil {
+			status.ErrorCategory = "apply_error"
+			status.ErrorMessage = err.Error()
+			status.FailedReloader = rl.name
+			if len(status.AppliedReloaders) > 0 && r.lastGood != nil {
+				status.RollbackAttempted = true
+				rollbackErr := r.rollback()
+				status.RollbackSuccessful = rollbackErr == nil
+				if rollbackErr != nil {
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed: %v", rl.name, err, rollbackErr)
+				}
+			}
+			return r.record(initial, status, fmt.Errorf("failed to apply configuration in reloader %q: %w", rl.name, err))
+		}
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+
+	r.lastGood = conf
+	status.LastReloadSuccessful = true
+	return r.record(initial, status, nil)
+}
+
+func (r *transactionalConfigReloader) rollback() error {
+	for _, rl := range r.reloaders {
+		if err := rl.reloader(r.lastGood); err != nil {
+			return fmt.Errorf("reloader %q: %w", rl.name, err)
+		}
+	}
+	updateGoGC(r.lastGood, r.logger)
+	r.noStepSubqueryInterval.Set(r.lastGood.GlobalConfig.EvaluationInterval)
+	return nil
+}
+
+func (r *transactionalConfigReloader) record(initial bool, status web.ReloadStatus, reloadErr error) error {
+	if initial {
+		return reloadErr
+	}
+	if err := r.status.Record(status); err != nil {
+		r.logger.Warn("Unable to persist transactional reload status", "err", err)
+	}
+	return reloadErr
+}

